#include <stdio.h>
#include <string.h>

struct Student {
  char name[50];
  int age;
};

void printStudent(struct Student s) {
  printf("%s, %d\n", s.name, s.age);
}

void celebrateBirthday(struct Student *s) {
  s->age++;
}

int main() {
  struct Student s = {"Alice", 20};
  printStudent(s);
  celebrateBirthday(&s);
  printf("After birthday: ");
  printStudent(s);
  return 0;
}
